import React, { useEffect, useState } from "react";
import MuteIcon from './img/mute.png'
import SoundIcon from './img/sound.png'
import Music from './img/Ordinary.ogg'
import "./style.css";

function App() {
  const [timeLeft, setTimeLeft] = useState({});
  const [musicOn, setMusicOn] = useState(true);

  const weddingDate = new Date("2026-06-01T18:00:00");

  const Mute = <img className="soundIcons" src={MuteIcon} alt="mute" />
  const Sound = <img className="soundIcons" src={SoundIcon} alt="sound" />

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      const diff = weddingDate - now;

      setTimeLeft({
        days: Math.floor(diff / (1000 * 60 * 60 * 24)),
        hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((diff / 1000 / 60) % 60),
        seconds: Math.floor((diff / 1000) % 60),
      });
    }, 1000);

    useEffect(() => {
  const audio = document.getElementById("music");

  const playMusic = () => {
    audio.play();
    document.removeEventListener("click", playMusic);
  };
  document.addEventListener("click", playMusic);
}, []);

    return () => clearInterval(timer);
  }, []);

  const toggleMusic = () => {
    const audio = document.getElementById("music");
    if (musicOn) {
      audio.pause();
    } else {
      audio.play();
    }
    setMusicOn(!musicOn);
  };

  const copyCard = () => {
    navigator.clipboard.writeText("8600 1234 5678 9012");
    alert("Karta nusxalandi!");
  };

  return (
    <section className="taklifnoma">
      <div className="container">
        <audio id="music" loop>
          <source src={Music} type="audio/mp3"/>
        </audio>

        <button className="music-btn" onClick={toggleMusic}>
          {musicOn ? Mute : Sound}
        </button>

        <h1 className="initials">F & M</h1>
        <h2 className="names">Farhod & Malika</h2>

        <img className="photo" src="https://via.placeholder.com/350x450" alt="couple"/>

        <p className="text">Sizni hayotimizdagi eng muhim kunga taklif qilamiz ❤️</p>

        <div className="countdown">
          {timeLeft.days} kun {timeLeft.hours} soat {timeLeft.minutes} daqiqa
        </div>

        <div className="info">📅 1 Iyun 2026 | ⏰ 18:00</div>

        <button className="btn" onClick={() => window.open("https://maps.google.com")}>
          📍 Lokatsiya
        </button>

        <div className="section">
          <h3>Sovg'a</h3>
          <p>8600 1234 5678 9012</p>
          <button className="btn" onClick={copyCard}>Nusxalash</button>
        </div>

        <div className="section">
          <h3>Aloqa</h3>
          <p>+998 90 123 45 67</p>
        </div>
      </div>
    </section>
  );
}

export default App;
